const data = $input.first().json;
const deals = data.results || [];

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

if (deals.length === 0) {
  return [{ json: { report: `📊 *Daily Deal Digest*\n_${today}_\n\nNo new deals in the last 24 hours.`, dealCount: 0 } }];
}

const sorted = deals
  .sort((a, b) => (Number(b.properties.fit_score) || 0) - (Number(a.properties.fit_score) || 0))
  .slice(0, 10);

let report = `📊 *Daily Deal Digest*\n`;
report += `_${today}_\n\n`;
report += `*Total New Deals: ${deals.length}*\n`;
report += `*Showing Top ${sorted.length} of ${deals.length} deals*\n\n`;
report += `━━━━━━━━━━━━━━━━\n\n`;

sorted.forEach((deal, i) => {
  const p = deal.properties;
  report += `${i + 1}. *${p.dealname}*\n`;
  report += `   📍 ${p.geography || 'N/A'} | 🏭 ${p.industry || 'N/A'}\n`;
  report += `   💰 Revenue: $${Number(p.annual_revenue).toLocaleString()}\n`;
  report += `   📈 EBITDA: $${Number(p.ebitda).toLocaleString()}\n`;
  report += `   ⭐ Fit Score: ${p.fit_score}/10\n`;
  report += `   📝 ${p.ai_summary || 'N/A'}\n`;
  report += `   🔗 ${p.listing_url || 'N/A'}\n\n`;
});

report += `━━━━━━━━━━━━━━━━\n`;
report += `🔗 Full Pipeline: https://app-na2.hubspot.com/deals/246226360`;

return [{ json: { report, dealCount: deals.length } }];

const data = $input.first().json;
const deals = data.results || [];

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toLocaleDateString('en-US', {
  month: 'long', day: 'numeric'
});

if (deals.length === 0) {
  return [{ json: { report: `📋 *Weekly Pipeline Report*\n_${weekStart} → ${today}_\n\nNo new deals this week.`, dealCount: 0 } }];
}

// Source breakdown
const bySource = {};
deals.forEach(d => {
  const src = d.properties.deal_source || 'Unknown';
  if (!bySource[src]) bySource[src] = 0;
  bySource[src]++;
});

// Score stats
const avgScore = (deals.reduce((sum, d) => sum + Number(d.properties.fit_score || 0), 0) / deals.length).toFixed(1);
const highFit = deals.filter(d => Number(d.properties.fit_score) >= 8).length;

// Top 10 by fit score
const sorted = deals
  .sort((a, b) => (Number(b.properties.fit_score) || 0) - (Number(a.properties.fit_score) || 0))
  .slice(0, 10);

let report = `📋 *Weekly Pipeline Report*\n`;
report += `_${weekStart} → ${today}_\n\n`;
report += `━━━━━━━━━━━━━━━━\n`;
report += `📦 *Total Deals: ${deals.length}*\n`;
report += `⭐ Avg Fit Score: ${avgScore}/10\n`;
report += `🔥 High Fit (8+): ${highFit}\n\n`;

report += `📌 *By Source:*\n`;
Object.entries(bySource).forEach(([src, count]) => {
  report += `  • ${src}: ${count}\n`;
});

report += `\n━━━━━━━━━━━━━━━━\n`;
report += `🏆 *Top ${sorted.length} Deals:*\n\n`;

sorted.forEach((deal, i) => {
  const p = deal.properties;
  report += `${i + 1}. *${p.dealname}*\n`;
  report += `   📍 ${p.geography || 'N/A'} | 🏭 ${p.industry || 'N/A'}\n`;
  report += `   💰 $${Number(p.annual_revenue).toLocaleString()}\n`;
  report += `   ⭐ Score: ${p.fit_score}/10\n\n`;
});

report += `━━━━━━━━━━━━━━━━\n`;
report += `🔗 Full Pipeline: https://app-na2.hubspot.com/deals/246226360`;

return [{ json: { report, dealCount: deals.length } }];
